import { defineComponentSlotStyle } from "@yamada-ui/react"
import { nativeSelectStyle } from "../native-select"

export const colorSelectorStyle = defineComponentSlotStyle({
  base: {
    alphaSlider: {},
    colorSwatchGroup: {
      display: "grid",
      gap: "1.5",
      gridTemplateColumns: "repeat({color-swatch-group-columns}, 1fr)",
    },
    colorSwatchGroupLabel: {
      fontSize: "sm",
      fontWeight: "medium",
      _disabled: { layerStyle: "disabled" },
    },
    colorSwatchItem: { w: "full", _disabled: { layerStyle: "disabled" } },
    eyeDropper: nativeSelectStyle.base?.icon,
    hueSlider: {},
    root: {
      display: "flex",
      flexDirection: "column",
      gap: "1.5",
      maxW: "full",
      w: "full",
    },
    saturationSlider: {},
  },

  props: {
    /**
     * The shape of the thumb and color swatch.
     *
     * @default 'circle'
     */
    shape: {
      circle: {},
      rounded: {},
      square: { colorSwatchItem: { rounded: "0" } },
    },
  },

  sizes: {
    xs: {},
    sm: {},
    md: {},
    lg: {},
    xl: {},
  },

  defaultProps: {
    size: "md",
  },
})

export type ColorSelectorStyle = typeof colorSelectorStyle

import { page, render } from "#test/browser"
import { ColorSelector } from "./"

const getTrackRect = (testId: string) => {
  const track = page.getByTestId(testId).element()

  if (!(track instanceof HTMLElement))
    throw new Error("Expected an HTMLElement")

  return { rect: track.getBoundingClientRect(), track }
}

const pointer = (
  target: EventTarget,
  type: "pointerdown" | "pointerup",
  x: number,
  y: number,
) => {
  target.dispatchEvent(
    new PointerEvent(type, { bubbles: true, clientX: x, clientY: y }),
  )
}

const keyDown = (element: Element, key: string, code?: string) => {
  element.dispatchEvent(
    new KeyboardEvent("keydown", { key, bubbles: true, code }),
  )
}

const click = (element: Element) => {
  element.dispatchEvent(new MouseEvent("click", { bubbles: true }))
}

describe("<ColorSelector />", () => {
  const defaultEyeDropper = (window as any).EyeDropper
  const openEyeDropper = vi.fn()

  class EyeDropperMock {
    open = openEyeDropper
  }

  beforeEach(() => {
    openEyeDropper.mockReset()
    vi.stubGlobal("EyeDropper", EyeDropperMock)
  })

  afterAll(() => {
    vi.stubGlobal("EyeDropper", defaultEyeDropper)
  })

  test("hue slider pointer interaction triggers onChange, onChangeStart and onChangeEnd", async () => {
    const onChange = vi.fn()
    const onChangeStart = vi.fn()
    const onChangeEnd = vi.fn()
    await render(
      <ColorSelector.Root
        defaultValue="#ff0000"
        hueSliderProps={{
          trackProps: { style: { width: 360 }, "data-testid": "hue-track" },
        }}
        onChange={onChange}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const { rect, track } = getTrackRect("hue-track")

    pointer(track, "pointerdown", rect.left + rect.width / 2, rect.top)
    expect(onChangeStart).toHaveBeenCalledWith(expect.any(String))

    pointer(window, "pointerup", rect.left + rect.width / 2, rect.top)
    expect(onChangeEnd).toHaveBeenCalledWith(expect.any(String))
  })

  test("saturation slider pointer interaction triggers onChangeStart and onChangeEnd", async () => {
    const onChangeStart = vi.fn()
    const onChangeEnd = vi.fn()
    await render(
      <ColorSelector.Root
        defaultValue="#ff0000"
        saturationSliderProps={{
          trackProps: {
            style: { height: 200, width: 200 },
            "data-testid": "saturation-track",
          },
        }}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const { rect, track } = getTrackRect("saturation-track")

    pointer(
      track,
      "pointerdown",
      rect.left + rect.width / 2,
      rect.top + rect.height / 2,
    )
    expect(onChangeStart).toHaveBeenCalledWith(expect.any(String))

    pointer(
      window,
      "pointerup",
      rect.left + rect.width / 2,
      rect.top + rect.height / 2,
    )
    expect(onChangeEnd).toHaveBeenCalledWith(expect.any(String))
  })

  test("alpha slider pointer interaction triggers onChangeStart and onChangeEnd", async () => {
    const onChangeStart = vi.fn()
    const onChangeEnd = vi.fn()
    await render(
      <ColorSelector.Root
        defaultValue="hsla(0, 100%, 50%, 0.5)"
        format="hsla"
        alphaSliderProps={{
          trackProps: { style: { width: 100 }, "data-testid": "alpha-track" },
        }}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const { rect, track } = getTrackRect("alpha-track")

    pointer(track, "pointerdown", rect.left + rect.width / 2, rect.top)
    expect(onChangeStart).toHaveBeenCalledWith(expect.any(String))

    pointer(window, "pointerup", rect.left + rect.width / 2, rect.top)
    expect(onChangeEnd).toHaveBeenCalledWith(expect.any(String))
  })

  test("does not trigger onChangeStart or onChangeEnd when disabled", async () => {
    const onChangeStart = vi.fn()
    const onChangeEnd = vi.fn()
    await render(
      <ColorSelector.Root
        defaultValue="#ff0000"
        disabled
        hueSliderProps={{
          trackProps: { style: { width: 360 }, "data-testid": "hue-track" },
        }}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const { rect, track } = getTrackRect("hue-track")

    pointer(track, "pointerdown", rect.left + rect.width / 2, rect.top)
    pointer(window, "pointerup", rect.left + rect.width / 2, rect.top)

    expect(onChangeStart).not.toHaveBeenCalled()
    expect(onChangeEnd).not.toHaveBeenCalled()
  })

  test("does not trigger onChangeStart or onChangeEnd when readOnly", async () => {
    const onChangeStart = vi.fn()
    const onChangeEnd = vi.fn()
    await render(
      <ColorSelector.Root
        defaultValue="#ff0000"
        readOnly
        hueSliderProps={{
          trackProps: { style: { width: 360 }, "data-testid": "hue-track" },
        }}
        onChangeEnd={onChangeEnd}
        onChangeStart={onChangeStart}
      />,
    )

    const { rect, track } = getTrackRect("hue-track")

    pointer(track, "pointerdown", rect.left + rect.width / 2, rect.top)
    pointer(window, "pointerup", rect.left + rect.width / 2, rect.top)

    expect(onChangeStart).not.toHaveBeenCalled()
    expect(onChangeEnd).not.toHaveBeenCalled()
  })

  test("eye dropper triggers color pick on click", async () => {
    openEyeDropper.mockResolvedValue({ sRGBHex: "#00ff00" })

    const onChange = vi.fn()
    const { user } = await render(
      <ColorSelector.Root defaultValue="#ff0000" onChange={onChange}>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    await user.click(page.getByTestId("eye-dropper"))

    await vi.waitFor(() => {
      expect(openEyeDropper).toHaveBeenCalledTimes(1)
      expect(onChange).toHaveBeenCalledWith("#00ff00")
    })
  })

  test("eye dropper triggers color pick on Enter key", async () => {
    openEyeDropper.mockResolvedValue({ sRGBHex: "#00ff00" })

    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ff0000" onChange={onChange}>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("eye-dropper").element(), "Enter")

    await vi.waitFor(() => {
      expect(openEyeDropper).toHaveBeenCalledTimes(1)
      expect(onChange).toHaveBeenCalledWith("#00ff00")
    })
  })

  test("eye dropper triggers color pick on Space key", async () => {
    openEyeDropper.mockResolvedValue({ sRGBHex: "#00ff00" })

    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ff0000" onChange={onChange}>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("eye-dropper").element(), " ", "Space")

    await vi.waitFor(() => {
      expect(openEyeDropper).toHaveBeenCalledTimes(1)
      expect(onChange).toHaveBeenCalledWith("#00ff00")
    })
  })

  test("eye dropper does not trigger when disabled", async () => {
    openEyeDropper.mockResolvedValue({ sRGBHex: "#00ff00" })

    await render(
      <ColorSelector.Root defaultValue="#ff0000" disabled>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    const eyeDropper = page.getByTestId("eye-dropper")

    await expect.element(eyeDropper).toHaveAttribute("aria-disabled", "true")
    await expect.element(eyeDropper).toHaveAttribute("tabindex", "-1")

    click(eyeDropper.element())

    expect(openEyeDropper).not.toHaveBeenCalled()
  })

  test("eye dropper does not trigger on Enter key when disabled", async () => {
    openEyeDropper.mockResolvedValue({ sRGBHex: "#00ff00" })

    await render(
      <ColorSelector.Root defaultValue="#ff0000" disabled>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("eye-dropper").element(), "Enter")

    expect(openEyeDropper).not.toHaveBeenCalled()
  })

  test("eye dropper does not trigger when readOnly", async () => {
    openEyeDropper.mockResolvedValue({ sRGBHex: "#00ff00" })

    await render(
      <ColorSelector.Root defaultValue="#ff0000" readOnly>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    const eyeDropper = page.getByTestId("eye-dropper")

    await expect.element(eyeDropper).toHaveAttribute("aria-disabled", "true")

    click(eyeDropper.element())

    expect(openEyeDropper).not.toHaveBeenCalled()
  })

  test("eye dropper handles null result gracefully", async () => {
    openEyeDropper.mockResolvedValue(null)

    const onChange = vi.fn()
    const { user } = await render(
      <ColorSelector.Root defaultValue="#ff0000" onChange={onChange}>
        <ColorSelector.EyeDropper data-testid="eye-dropper" />
      </ColorSelector.Root>,
    )

    await user.click(page.getByTestId("eye-dropper"))

    await vi.waitFor(() => {
      expect(openEyeDropper).toHaveBeenCalledTimes(1)
    })

    expect(onChange).not.toHaveBeenCalled()
  })

  test("calls onChange when clicking a color swatch item", async () => {
    const onChange = vi.fn()
    const { user } = await render(
      <ColorSelector.Root defaultValue="#ffffff" onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-2"
            value="#0000ff"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    await user.click(page.getByTestId("swatch-1"))

    expect(onChange).toHaveBeenCalledWith("#00ff00")
  })

  test("calls onChange when pressing Enter on a color swatch item", async () => {
    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ffffff" onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-2"
            value="#0000ff"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("swatch-0").element(), "Enter")

    expect(onChange).toHaveBeenCalledWith("#ff0000")
  })

  test("calls onChange when pressing Space on a color swatch item", async () => {
    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ffffff" onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-2"
            value="#0000ff"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("swatch-0").element(), " ", "Space")

    expect(onChange).toHaveBeenCalledWith("#ff0000")
  })

  test("does not call onChange on swatch click when disabled", async () => {
    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ffffff" disabled onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    click(page.getByTestId("swatch-0").element())

    expect(onChange).not.toHaveBeenCalled()
  })

  test("does not call onChange on swatch click when readOnly", async () => {
    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ffffff" readOnly onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    click(page.getByTestId("swatch-0").element())

    expect(onChange).not.toHaveBeenCalled()
  })

  test("color swatch item does not trigger onChange on keyDown when disabled", async () => {
    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ffffff" disabled onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("swatch-0").element(), "Enter")

    expect(onChange).not.toHaveBeenCalled()
  })

  test("color swatch item does not trigger onChange on keyDown when readOnly", async () => {
    const onChange = vi.fn()
    await render(
      <ColorSelector.Root defaultValue="#ffffff" readOnly onChange={onChange}>
        <ColorSelector.ColorSwatchGroup>
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-0"
            value="#ff0000"
          />
          <ColorSelector.ColorSwatchItem
            data-testid="swatch-1"
            value="#00ff00"
          />
        </ColorSelector.ColorSwatchGroup>
      </ColorSelector.Root>,
    )

    keyDown(page.getByTestId("swatch-0").element(), " ", "Space")

    expect(onChange).not.toHaveBeenCalled()
  })
})

"use client"

import type { ReactNode } from "react"
import type { HTMLStyledProps, StyleValue, ThemeProps, Merge } from "@yamada-ui/react"
import type { ColorSwatchProps } from "../color-swatch"
import type { ColorSelectorStyle } from "./color-selector.style"
import type {
  UseColorSelectorProps,
  UseColorSelectorReturn,
} from "./use-color-selector"
import { useMemo } from "react"
import { createSlotComponent, mergeProps, styled, varAttr } from "@yamada-ui/react"
import { AlphaSlider } from "../alpha-slider"
import { ColorSwatch } from "../color-swatch"
import { HueSlider } from "../hue-slider"
import { PipetteIcon } from "../icon"
import { SaturationSlider } from "../saturation-slider"
import { colorSelectorStyle } from "./color-selector.style"
import { useColorSelector } from "./use-color-selector"

interface ComponentContext
  extends
    Pick<
      ColorSelectorRootProps,
      | "alphaSliderProps"
      | "colorSwatches"
      | "colorSwatchGroupLabelProps"
      | "colorSwatchGroupProps"
      | "colorSwatchItemProps"
      | "hueSliderProps"
      | "saturationSliderProps"
      | "shape"
      | "size"
    >,
    Pick<
      UseColorSelectorReturn,
      | "alpha"
      | "getAlphaSliderProps"
      | "getColorSwatchGroupLabelProps"
      | "getColorSwatchGroupProps"
      | "getColorSwatchItemProps"
      | "getEyeDropperProps"
      | "getHueSliderProps"
      | "getSaturationSliderProps"
    > {}

export interface ColorSelectorRootProps
  extends
    Merge<HTMLStyledProps, UseColorSelectorProps>,
    ThemeProps<ColorSelectorStyle> {
  /**
   * An array of colors in one of the supported formats.
   * Used to render swatches list below the color selector.
   */
  colorSwatches?: string[]
  /**
   * The number of columns in the color swatch group.
   *
   * @default 8
   */
  colorSwatchGroupColumns?: StyleValue<number>
  /**
   * The label of the color swatch group.
   */
  colorSwatchGroupLabel?: ReactNode
  /**
   * If `true`, the alpha slider will be displayed.
   *
   * @default false
   */
  withAlpha?: boolean
  /**
   * Props for the alpha slider.
   */
  alphaSliderProps?: ColorSelectorAlphaSliderProps
  /**
   * Props for the color swatch group label.
   */
  colorSwatchGroupLabelProps?: ColorSelectorColorSwatchGroupLabelProps
  /**
   * Props for the color swatch group.
   */
  colorSwatchGroupProps?: ColorSelectorColorSwatchGroupProps
  /**
   * Props for the color swatch item.
   */
  colorSwatchItemProps?: Omit<ColorSelectorColorSwatchItemProps, "value">
  /**
   * Props for the hue slider.
   */
  hueSliderProps?: ColorSelectorHueSliderProps
  /**
   * Props for the saturation slider.
   */
  saturationSliderProps?: ColorSelectorSaturationSliderProps
}

const {
  ComponentContext,
  PropsContext: ColorSelectorPropsContext,
  useComponentContext,
  usePropsContext: useColorSelectorPropsContext,
  withContext,
  withProvider,
} = createSlotComponent<
  ColorSelectorRootProps,
  ColorSelectorStyle,
  ComponentContext
>("color-selector", colorSelectorStyle)

export { ColorSelectorPropsContext, useColorSelectorPropsContext }

/**
 * `ColorSelector` is a component used by the user to select a color.
 *
 * @see https://yamada-ui.com/docs/components/color-selector
 */
export const ColorSelectorRoot = withProvider<
  "div",
  ColorSelectorRootProps,
  "shape" | "size"
>(
  ({
    size,
    children,
    colorSwatches,
    colorSwatchGroupLabel,
    shape,
    withAlpha,
    alphaSliderProps,
    colorSwatchGroupLabelProps,
    colorSwatchGroupProps,
    colorSwatchItemProps,
    hueSliderProps,
    saturationSliderProps,
    ...rest
  }) => {
    const {
      alpha,
      getAlphaSliderProps,
      getColorSwatchGroupLabelProps,
      getColorSwatchGroupProps,
      getColorSwatchItemProps,
      getEyeDropperProps,
      getHueSliderProps,
      getRootProps,
      getSaturationSliderProps,
    } = useColorSelector(rest)
    const computedChildren = useMemo(() => {
      if (children) return children

      return (
        <>
          <ColorSelectorSaturationSlider />
          <ColorSelectorHueSlider />
          <ColorSelectorAlphaSlider />

          {colorSwatchGroupLabel ? (
            <ColorSelectorColorSwatchGroupLabel>
              {colorSwatchGroupLabel}
            </ColorSelectorColorSwatchGroupLabel>
          ) : null}
          {colorSwatches ? <ColorSelectorColorSwatchGroup /> : null}
        </>
      )
    }, [children, colorSwatchGroupLabel, colorSwatches])
    const context = useMemo(
      () => ({
        size,
        alpha: withAlpha ?? alpha,
        colorSwatches,
        colorSwatchGroupLabel,
        shape,
        alphaSliderProps,
        colorSwatchGroupLabelProps,
        colorSwatchGroupProps,
        colorSwatchItemProps,
        getAlphaSliderProps,
        getColorSwatchGroupLabelProps,
        getColorSwatchGroupProps,
        getColorSwatchItemProps,
        getEyeDropperProps,
        getHueSliderProps,
        getSaturationSliderProps,
        hueSliderProps,
        saturationSliderProps,
      }),
      [
        size,
        withAlpha,
        alpha,
        shape,
        colorSwatches,
        colorSwatchGroupLabel,
        alphaSliderProps,
        getAlphaSliderProps,
        getEyeDropperProps,
        getHueSliderProps,
        getSaturationSliderProps,
        getColorSwatchGroupLabelProps,
        getColorSwatchGroupProps,
        getColorSwatchItemProps,
        hueSliderProps,
        saturationSliderProps,
        colorSwatchGroupLabelProps,
        colorSwatchGroupProps,
        colorSwatchItemProps,
      ],
    )

    return (
      <ComponentContext value={context}>
        <styled.div {...getRootProps()}>{computedChildren}</styled.div>
      </ComponentContext>
    )
  },
  "root",
  { transferProps: ["size", "shape"] },
)(undefined, ({ colorSwatchGroupColumns = 8, ...rest }) => ({
  "--color-swatch-group-columns": varAttr(colorSwatchGroupColumns),
  ...rest,
}))

export interface ColorSelectorSaturationSliderProps
  extends SaturationSlider.RootProps {}

export const ColorSelectorSaturationSlider = withContext<
  "input",
  ColorSelectorSaturationSliderProps
>((props) => {
  const { size, shape, getSaturationSliderProps, saturationSliderProps } =
    useComponentContext()

  return (
    <SaturationSlider.Root
      size={size}
      shape={shape}
      {...getSaturationSliderProps(mergeProps(saturationSliderProps, props)())}
    />
  )
}, "saturationSlider")()

export interface ColorSelectorHueSliderProps extends HueSlider.RootProps {}

export const ColorSelectorHueSlider = withContext<
  "input",
  ColorSelectorHueSliderProps
>((props) => {
  const { size, shape, getHueSliderProps, hueSliderProps } =
    useComponentContext()

  return (
    <HueSlider.Root
      size={size}
      shape={shape}
      {...getHueSliderProps(mergeProps(hueSliderProps, props)())}
    />
  )
}, "hueSlider")()

export interface ColorSelectorAlphaSliderProps extends Partial<AlphaSlider.RootProps> {}

export const ColorSelectorAlphaSlider = withContext<
  "input",
  ColorSelectorAlphaSliderProps
>((props) => {
  const { size, alpha, shape, alphaSliderProps, getAlphaSliderProps } =
    useComponentContext()

  if (!alpha) return null

  return (
    <AlphaSlider.Root
      size={size}
      shape={shape}
      {...getAlphaSliderProps(mergeProps(alphaSliderProps, props)())}
    />
  )
}, "alphaSlider")()

export interface ColorSelectorEyeDropperProps extends HTMLStyledProps {
  /**
   * The icon to display in the eye dropper.
   */
  icon?: ReactNode
}

export const ColorSelectorEyeDropper = withContext<
  "div",
  ColorSelectorEyeDropperProps
>("div", "eyeDropper")(undefined, ({ children, icon, ...rest }) => {
  const { getEyeDropperProps } = useComponentContext()

  return getEyeDropperProps({
    children: icon || children || <PipetteIcon />,
    ...rest,
  })
})

export interface ColorSelectorColorSwatchGroupLabelProps extends HTMLStyledProps<"span"> {}

export const ColorSelectorColorSwatchGroupLabel = withContext<
  "span",
  ColorSelectorColorSwatchGroupLabelProps
>("span", "colorSwatchGroupLabel")(undefined, (props) => {
  const { colorSwatchGroupLabelProps, getColorSwatchGroupLabelProps } =
    useComponentContext()

  return getColorSwatchGroupLabelProps(
    mergeProps(colorSwatchGroupLabelProps, props)(),
  )
})

export interface ColorSelectorColorSwatchGroupProps extends HTMLStyledProps {}

export const ColorSelectorColorSwatchGroup = withContext<
  "div",
  ColorSelectorColorSwatchGroupProps
>("div", "colorSwatchGroup")(undefined, ({ children, ...rest }) => {
  const { colorSwatches, colorSwatchGroupProps, getColorSwatchGroupProps } =
    useComponentContext()
  const computedChildren =
    children ??
    colorSwatchGroupProps?.children ??
    colorSwatches?.map((value, index) => (
      <ColorSelectorColorSwatchItem key={index} value={value} />
    ))

  return getColorSwatchGroupProps(
    mergeProps(colorSwatchGroupProps, rest, { children: computedChildren })(),
  )
})

export interface ColorSelectorColorSwatchItemProps extends Omit<
  ColorSwatchProps,
  "color"
> {
  /**
   * The value of the color swatch.
   */
  value: string
}

export const ColorSelectorColorSwatchItem = withContext<
  "div",
  ColorSelectorColorSwatchItemProps
>(ColorSwatch, "colorSwatchItem")(undefined, (props) => {
  const { colorSwatchItemProps, getColorSwatchItemProps } =
    useComponentContext()

  return getColorSwatchItemProps(mergeProps(colorSwatchItemProps, props)())
})

"use client"

import type {
  HTMLProps,
  PropGetter,
  RequiredPropGetter,
  ColorFormat,
} from "@yamada-ui/react"
import type { UseSaturationSliderProps } from "../saturation-slider"
import type { UseSliderProps } from "../slider"
import { useCallback, useId, useRef, useState } from "react"
import {
  mergeProps,
  ariaAttr,
  calcFormat,
  convertColor,
  cx,
  dataAttr,
  handlerAll,
  hsvTo,
  isString,
  parseToHsv,
  runKeyAction,
  sameColor,
  useUpdateEffect,
} from "@yamada-ui/react"
import { useControllableState } from "../../hooks/use-controllable-state"
import { useEyeDropper } from "../../hooks/use-eye-dropper"
import { useI18n } from "../../providers/i18n-provider"

type Hsva = [number, number, number, number]

export interface UseColorSelectorProps extends Omit<HTMLProps, "onChange"> {
  /**
   * The initial value of the color selector.
   *
   * @default fallbackValue
   */
  defaultValue?: string
  /**
   * If `true`, the color selector will be disabled.
   *
   * @default false
   */
  disabled?: boolean
  /**
   * The fallback value of the color selector.
   *
   * @default '#FFFFFF'
   */
  fallbackValue?: string
  /**
   * The format of the color selector.
   * Automatically determines the format of `value` or `defaultValue`.
   *
   * @default 'hex'
   */
  format?: ColorFormat
  /**
   * If `true`, the color selector will be read only.
   *
   * @default false
   */
  readOnly?: boolean
  /**
   * The value of the color selector.
   */
  value?: string
  /**
   * The callback invoked when the value changes.
   */
  onChange?: (value: string) => void
  /**
   * The callback invoked when the value changes ends.
   */
  onChangeEnd?: (value: string) => void
  /**
   * The callback invoked when the value changes starts.
   */
  onChangeStart?: (value: string) => void
}

export const useColorSelector = ({
  fallbackValue = "#FFFFFF",
  defaultValue = fallbackValue,
  disabled = false,
  format: formatProp,
  readOnly = false,
  value: valueProp,
  onChange: onChangeProp,
  onChangeEnd: onChangeEndProp,
  onChangeStart: onChangeStartProp,
  ...rest
}: UseColorSelectorProps) => {
  const { t } = useI18n("colorSelector")
  const format = formatProp ?? calcFormat(valueProp ?? defaultValue)
  const alpha = format.endsWith("a")
  const [value, setValue] = useControllableState({
    defaultValue,
    value: valueProp,
    onChange: onChangeProp,
  })
  const [hsva, setHsva] = useState(parseToHsv(value, fallbackValue))
  const [h, s, v, a] = hsva
  const interactive = !(disabled || readOnly)
  const swatchGroupLabelId = useId()
  const activeRef = useRef(false)
  const { supported: supportedEyeDropper, onOpen: onOpenEyeDropper } =
    useEyeDropper()
  const color = hsvTo([h, s, v, 1], fallbackValue)("hex")

  const onChange = useCallback(
    (value: Hsva | string) => {
      if (!interactive) return

      if (isString(value)) {
        setValue(convertColor(value, fallbackValue)(format))
        setHsva(parseToHsv(value, fallbackValue))
      } else {
        setHsva(value)
        setValue(hsvTo(value, fallbackValue)(format))
      }
    },
    [fallbackValue, format, interactive, setValue],
  )

  const onChangeStart = useCallback(
    ([h, s, v, a]: Hsva) => {
      if (!interactive) return

      activeRef.current = true

      const value = hsvTo([h, s, v, a], fallbackValue)(format)

      onChangeStartProp?.(value)
    },
    [interactive, fallbackValue, format, onChangeStartProp],
  )

  const onChangeEnd = useCallback(
    ([h, s, v, a]: Hsva) => {
      if (!interactive) return

      activeRef.current = false

      const value = hsvTo([h, s, v, a], fallbackValue)(format)

      onChangeEndProp?.(value)
    },
    [interactive, fallbackValue, format, onChangeEndProp],
  )

  const onEyeDropperClick = useCallback(async () => {
    if (!interactive) return

    const result = await onOpenEyeDropper()

    if (result?.sRGBHex) onChange(result.sRGBHex)
  }, [interactive, onChange, onOpenEyeDropper])

  useUpdateEffect(() => {
    if (activeRef.current) return

    if (valueProp) setHsva(parseToHsv(valueProp, fallbackValue))
  }, [valueProp])

  const getRootProps: PropGetter = useCallback(
    (props = {}) =>
      mergeProps(
        {
          "data-disabled": dataAttr(disabled),
          "data-readonly": dataAttr(readOnly),
        },
        rest,
        props,
      )(),
    [disabled, readOnly, rest],
  )

  const getSaturationSliderProps: PropGetter<UseSaturationSliderProps> =
    useCallback(
      (props = {}) => ({
        disabled,
        readOnly,
        value: [h, s, v],
        ...props,
        onChange: handlerAll(props.onChange, ([h, s, v]) =>
          onChange([h, s, v, a]),
        ),
        onChangeEnd: handlerAll(props.onChangeEnd, ([h, s, v]) =>
          onChangeEnd([h, s, v, a]),
        ),
        onChangeStart: handlerAll(props.onChangeStart, ([h, s, v]) =>
          onChangeStart([h, s, v, a]),
        ),
      }),
      [disabled, readOnly, h, s, v, onChange, a, onChangeEnd, onChangeStart],
    )

  const getHueSliderProps: PropGetter<
    Omit<UseSliderProps, "betweenThumbs" | "orientation">
  > = useCallback(
    (props = {}) => ({
      disabled,
      readOnly,
      value: h,
      ...props,
      onChange: handlerAll(props.onChange, (h) => onChange([h, s, v, a])),
      onChangeEnd: handlerAll(props.onChangeEnd, (h) =>
        onChangeEnd([h, s, v, a]),
      ),
      onChangeStart: handlerAll(props.onChangeStart, (h) =>
        onChangeStart([h, s, v, a]),
      ),
    }),
    [disabled, readOnly, h, onChange, s, v, a, onChangeEnd, onChangeStart],
  )

  const getAlphaSliderProps: PropGetter<
    Omit<UseSliderProps, "betweenThumbs" | "orientation">,
    undefined,
    Omit<UseSliderProps, "betweenThumbs" | "orientation"> & { color: string }
  > = useCallback(
    (props = {}) => ({
      color,
      disabled,
      readOnly,
      value: a,
      ...props,
      onChange: handlerAll(props.onChange, (a) => onChange([h, s, v, a])),
      onChangeEnd: handlerAll(props.onChangeEnd, (a) =>
        onChangeEnd([h, s, v, a]),
      ),
      onChangeStart: handlerAll(props.onChangeStart, (a) =>
        onChangeStart([h, s, v, a]),
      ),
    }),
    [
      color,
      disabled,
      readOnly,
      a,
      onChange,
      h,
      s,
      v,
      onChangeEnd,
      onChangeStart,
    ],
  )

  const getEyeDropperProps: PropGetter = useCallback(
    (props = {}) => ({
      "aria-disabled": ariaAttr(!interactive),
      "aria-label": t("Pick a color"),
      "data-disabled": dataAttr(disabled),
      "data-readonly": dataAttr(readOnly),
      hidden: !supportedEyeDropper,
      role: "button",
      tabIndex: interactive ? 0 : -1,
      ...props,
      onClick: handlerAll(props.onClick, onEyeDropperClick),
      onKeyDown: handlerAll(props.onKeyDown, (ev) =>
        runKeyAction(ev, {
          Enter: onEyeDropperClick,
          Space: onEyeDropperClick,
        }),
      ),
    }),
    [
      disabled,
      interactive,
      onEyeDropperClick,
      readOnly,
      supportedEyeDropper,
      t,
    ],
  )

  const getColorSwatchGroupLabelProps: PropGetter<"span"> = useCallback(
    (props) => ({
      id: swatchGroupLabelId,
      "data-disabled": dataAttr(disabled),
      "data-readonly": dataAttr(readOnly),
      ...props,
    }),
    [swatchGroupLabelId, disabled, readOnly],
  )

  const getColorSwatchGroupProps: PropGetter = useCallback(
    ({ "aria-labelledby": ariaLabelledby, ...props } = {}) => ({
      "aria-labelledby": cx(ariaLabelledby, swatchGroupLabelId),
      "data-disabled": dataAttr(disabled),
      "data-readonly": dataAttr(readOnly),
      role: "listbox",
      ...props,
    }),
    [swatchGroupLabelId, disabled, readOnly],
  )

  const getColorSwatchItemProps: RequiredPropGetter<
    "div",
    { value: string },
    HTMLProps & { color: string }
  > = useCallback(
    ({ value, ...props }) => ({
      "aria-disabled": ariaAttr(!interactive),
      "aria-selected": sameColor(value, color),
      "data-disabled": dataAttr(disabled),
      "data-readonly": dataAttr(readOnly),
      role: "option",
      tabIndex: interactive ? 0 : -1,
      ...props,
      color: value,
      onClick: handlerAll(props.onClick, () => onChange(value)),
      onKeyDown: handlerAll(props.onKeyDown, (ev) =>
        runKeyAction(ev, {
          Enter: () => onChange(value),
          Space: () => onChange(value),
        }),
      ),
    }),
    [disabled, color, interactive, onChange, readOnly],
  )

  return {
    alpha,
    format,
    setValue,
    value,
    getAlphaSliderProps,
    getColorSwatchGroupLabelProps,
    getColorSwatchGroupProps,
    getColorSwatchItemProps,
    getEyeDropperProps,
    getHueSliderProps,
    getRootProps,
    getSaturationSliderProps,
    onChange,
  }
}

export type UseColorSelectorReturn = ReturnType<typeof useColorSelector>
